+        let dir = tempfile::tempdir().expect("tempdir");
+        let path = dir.path().join("uring_roundtrip.db");
+
+        let (mut file, _) = vfs
+            .open(&cx, Some(&path), open_flags_create())
+            .expect("open should succeed");
+        file.write(&cx, b"hello io_uring", 0)
